const { ethers } = require("ethers");
const readline = require("readline");

// ============================================================
// CONFIGURATION & CONSTANTS
// ============================================================

const SUPPORTED_NETWORKS = {
  mainnet: {
    chainId: 1,
    rpcUrl: "https://eth.llamarpc.com",
    name: "Ethereum Mainnet",
  },
  goerli: {
    chainId: 5,
    rpcUrl: "https://ethereum-goerli.publicnode.com",
    name: "Goerli Testnet",
  },
  sepolia: {
    chainId: 11155111,
    rpcUrl: "https://ethereum-sepolia.publicnode.com",
    name: "Sepolia Testnet",
  },
};

// Allowlisted contract addresses (only interact with known contracts)
const ALLOWLISTED_CONTRACTS = new Map();

// Maximum gas limit to prevent excessive spending
const MAX_GAS_LIMIT = 500000n;

// Maximum ETH value per transaction (in wei)
const MAX_TRANSACTION_VALUE = ethers.parseEther("1.0");

// Rate limiting: minimum milliseconds between transactions
const MIN_TRANSACTION_INTERVAL_MS = 5000;

// ============================================================
// INPUT VALIDATION
// ============================================================

class InputValidator {
  static isValidAddress(address) {
    if (typeof address !== "string") return false;
    try {
      ethers.getAddress(address); // checksums and validates
      return true;
    } catch {
      return false;
    }
  }

  static sanitizeAddress(address) {
    if (!this.isValidAddress(address)) {
      throw new Error(`Invalid Ethereum address: ${address}`);
    }
    return ethers.getAddress(address); // returns checksummed address
  }

  static isValidFunctionName(name) {
    if (typeof name !== "string") return false;
    // Only allow valid Solidity function name characters
    return /^[a-zA-Z_][a-zA-Z0-9_]*$/.test(name) && name.length <= 256;
  }

  static isValidABI(abiString) {
    try {
      const parsed = JSON.parse(abiString);
      if (!Array.isArray(parsed)) return false;
      // Validate each ABI entry has expected structure
      for (const entry of parsed) {
        if (typeof entry !== "object" || entry === null) return false;
        if (
          entry.type &&
          !["function", "event", "constructor", "fallback", "receive"].includes(
            entry.type
          )
        ) {
          return false;
        }
      }
      return true;
    } catch {
      return false;
    }
  }

  static sanitizeUint256(value) {
    if (typeof value !== "string") {
      throw new Error("Value must be a string");
    }
    // Remove whitespace
    const trimmed = value.trim();
    // Only allow digits and optional decimal point for ether values
    if (!/^\d+(\.\d+)?$/.test(trimmed)) {
      throw new Error(`Invalid numeric value: ${trimmed}`);
    }
    return trimmed;
  }

  static sanitizeNetworkName(network) {
    if (typeof network !== "string") {
      throw new Error("Network name must be a string");
    }
    const normalized = network.trim().toLowerCase();
    if (!SUPPORTED_NETWORKS[normalized]) {
      throw new Error(
        `Unsupported network: ${normalized}. Supported: ${Object.keys(SUPPORTED_NETWORKS).join(", ")}`
      );
    }
    return normalized;
  }

  static validateFunctionArgs(args, abiInputs) {
    if (args.length !== abiInputs.length) {
      throw new Error(
        `Expected ${abiInputs.length} arguments, got ${args.length}`
      );
    }
    const sanitized = [];
    for (let i = 0; i < abiInputs.length; i++) {
      const input = abiInputs[i];
      const arg = args[i];
      sanitized.push(this.sanitizeArgByType(arg, input.type, input.name));
    }
    return sanitized;
  }

  static sanitizeArgByType(value, solidityType, paramName) {
    if (typeof value !== "string") {
      throw new Error(`Parameter ${paramName} must be provided as a string`);
    }
    const trimmed = value.trim();

    if (solidityType === "address") {
      return this.sanitizeAddress(trimmed);
    }

    if (solidityType.startsWith("uint") || solidityType.startsWith("int")) {
      if (!/^-?\d+$/.test(trimmed)) {
        throw new Error(
          `Parameter ${paramName} must be a valid integer for type ${solidityType}`
        );
      }
      return BigInt(trimmed);
    }

    if (solidityType === "bool") {
      if (trimmed !== "true" && trimmed !== "false") {
        throw new Error(
          `Parameter ${paramName} must be 'true' or 'false' for type bool`
        );
      }
      return trimmed === "true";
    }

    if (solidityType === "string") {
      // Limit string length to prevent abuse
      if (trimmed.length > 10000) {
        throw new Error(
          `Parameter ${paramName} string too long (max 10000 chars)`
        );
      }
      return trimmed;
    }

    if (solidityType.startsWith("bytes")) {
      if (!/^0x[0-9a-fA-F]*$/.test(trimmed)) {
        throw new Error(
          `Parameter ${paramName} must be valid hex bytes for type ${solidityType}`
        );
      }
      return trimmed;
    }

    throw new Error(`Unsupported Solidity type: ${solidityType}`);
  }
}

// ============================================================
// SECURE WALLET MANAGER
// ============================================================

class SecureWalletManager {
  constructor() {
    this._wallet = null;
    this._provider = null;
    this._networkName = null;
  }

  async connect(networkName) {
    const sanitizedNetwork = InputValidator.sanitizeNetworkName(networkName);
    const networkConfig = SUPPORTED_NETWORKS[sanitizedNetwork];

    this._provider = new ethers.JsonRpcProvider(
      networkConfig.rpcUrl,
      networkConfig.chainId
    );

    // Verify the chain ID matches to prevent chain spoofing
    const network = await this._provider.getNetwork();
    if (Number(network.chainId) !== networkConfig.chainId) {
      throw new Error(
        `Chain ID mismatch! Expected ${networkConfig.chainId}, got ${network.chainId}`
      );
    }

    this._networkName = sanitizedNetwork;
    console.log(`Connected to ${networkConfig.name} (chainId: ${networkConfig.chainId})`);
  }

  async loadWalletFromEnv() {
    // SECURE: Read private key from environment variable, never from user input or plaintext files
    const privateKey = process.env.WALLET_PRIVATE_KEY;
    if (!privateKey) {
      throw new Error(
        "WALLET_PRIVATE_KEY environment variable not set. Set it securely before running."
      );
    }

    if (!this._provider) {
      throw new Error("Connect to a network first");
    }

    try {
      this._wallet = new ethers.Wallet(privateKey, this._provider);
    } catch (error) {
      throw new Error("Invalid private key format in WALLET_PRIVATE_KEY");
    }

    // SECURE: Never log the private key or full address in production
    const address = this._wallet.address;
    const maskedAddress = `${address.slice(0, 6)}...${address.slice(-4)}`;
    console.log(`Wallet loaded: ${maskedAddress}`);

    return maskedAddress;
  }

  get wallet() {
    if (!this._wallet) {
      throw new Error("Wallet not loaded");
    }
    return this._wallet;
  }

  get provider() {
    if (!this._provider) {
      throw new Error("Provider not connected");
    }
    return this._provider;
  }

  get networkName() {
    return this._networkName;
  }
}

// ============================================================
// CONTRACT ALLOWLIST MANAGER
// ============================================================

class ContractAllowlistManager {
  static addContract(address, abi, label) {
    const sanitizedAddress = InputValidator.sanitizeAddress(address);
    ALLOWLISTED_CONTRACTS.set(sanitizedAddress, {
      abi: JSON.parse(abi),
      label: label || "Unknown Contract",
      addedAt: new Date().toISOString(),
    });
    console.log(`Contract allowlisted: ${label} (${sanitizedAddress})`);
  }

  static isAllowlisted(address) {
    const sanitizedAddress = InputValidator.sanitizeAddress(address);
    return ALLOWLISTED_CONTRACTS.has(sanitizedAddress);
  }

  static getContractInfo(address) {
    const sanitizedAddress = InputValidator.sanitizeAddress(address);
    if (!ALLOWLISTED_CONTRACTS.has(sanitizedAddress)) {
      throw new Error(
        `Contract ${sanitizedAddress} is not in the allowlist. Add it first.`
      );
    }
    return ALLOWLISTED_CONTRACTS.get(sanitizedAddress);
  }

  static listContracts() {
    if (ALLOWLISTED_CONTRACTS.size === 0) {
      console.log("No contracts in allowlist.");
      return;
    }
    console.log("\nAllowlisted Contracts:");
    console.log("=".repeat(60));
    for (const [address, info] of ALLOWLISTED_CONTRACTS) {
      console.log(`  ${info.label}: ${address}`);
    }
    console.log("=".repeat(60));
  }
}

// ============================================================
// TRANSACTION BUILDER (Secure)
// ============================================================

class SecureTransactionBuilder {
  constructor(walletManager) {
    this._walletManager = walletManager;
    this._lastTransactionTime = 0;
    this._nonce = null;
  }

  _enforceRateLimit() {
    const now = Date.now();
    const elapsed = now - this._lastTransactionTime;
    if (elapsed < MIN_TRANSACTION_INTERVAL_MS) {
      throw new Error(
        `Rate limited. Wait ${MIN_TRANSACTION_INTERVAL_MS - elapsed}ms before next transaction.`
      );
    }
  }

  async _getSecureNonce() {
    // Always fetch the latest nonce from the network to prevent replay
    const nonce = await this._walletManager.provider.getTransactionCount(
      this._walletManager.wallet.address,
      "pending"
    );
    return nonce;
  }

  async buildReadTransaction(contractAddress, functionName, args) {
    // Validate contract is allowlisted
    const contractInfo =
      ContractAllowlistManager.getContractInfo(contractAddress);
    const sanitizedAddress = InputValidator.sanitizeAddress(contractAddress);

    if (!InputValidator.isValidFunctionName(functionName)) {
      throw new Error(`Invalid function name: ${functionName}`);
    }

    const contract = new ethers.Contract(
      sanitizedAddress,
      contractInfo.abi,
      this._walletManager.provider
    );

    // Verify the function exists in the ABI
    const fragment = contract.interface.getFunction(functionName);
    if (!fragment) {
      throw new Error(
        `Function ${functionName} not found in contract ABI`
      );
    }

    // Validate and sanitize arguments
    const sanitizedArgs = InputValidator.validateFunctionArgs(
      args,
      fragment.inputs
    );

    console.log(`\nRead call: ${contractInfo.label}.${functionName}()`);
    console.log(`  Contract: ${sanitizedAddress}`);
    console.log(`  Arguments: ${sanitizedArgs.map(String).join(", ") || "(none)"}`);

    // Execute read call (no transaction signing needed)
    const result = await contract[functionName](...sanitizedArgs);
    return result;
  }

  async buildWriteTransaction(
    contractAddress,
    functionName,
    args,
    valueInEther
  ) {
    this._enforceRateLimit();

    // Validate contract is allowlisted
    const contractInfo =
      ContractAllowlistManager.getContractInfo(contractAddress);
    const sanitizedAddress = InputValidator.sanitizeAddress(contractAddress);

    if (!InputValidator.isValidFunctionName(functionName)) {
      throw new Error(`Invalid function name: ${functionName}`);
    }

    const contract = new ethers.Contract(
      sanitizedAddress,
      contractInfo.abi,
      this._walletManager.wallet
    );

    // Verify the function exists
    const fragment = contract.interface.getFunction(functionName);
    if (!fragment) {
      throw new Error(
        `Function ${functionName} not found in contract ABI`
      );
    }

    // Check function is not view/pure (those should use read)
    if (
      fragment.stateMutability === "view" ||
      fragment.stateMutability === "pure"
    ) {
      throw new Error(
        `Function ${functionName} is ${fragment.stateMutability}. Use read call instead.`
      );
    }

    // Validate and sanitize arguments
    const sanitizedArgs = InputValidator.validateFunctionArgs(
      args,
      fragment.inputs
    );

    // Validate value
    let valueWei = 0n;
    if (valueInEther && valueInEther !== "0") {
      const sanitizedValue = InputValidator.sanitizeUint256(valueInEther);
      valueWei = ethers.parseEther(sanitizedValue);

      if (valueWei > MAX_TRANSACTION_VALUE) {
        throw new Error(
          `Transaction value ${sanitizedValue} ETH exceeds maximum allowed (${ethers.formatEther(MAX_TRANSACTION_VALUE)} ETH)`
        );
      }

      // Only allow value if function is payable
      if (fragment.stateMutability !== "payable") {
        throw new Error(
          `Function ${functionName} is not payable but value was provided`
        );
      }
    }

    // Estimate gas with safety margin
    let estimatedGas;
    try {
      const overrides = valueWei > 0n ? { value: valueWei } : {};
      estimatedGas = await contract[functionName].estimateGas(
        ...sanitizedArgs,
        overrides
      );
    } catch (error) {
      throw new Error(
        `Gas estimation failed (transaction would likely revert): ${error.message}`
      );
    }

    // Add 20% buffer to gas estimate
    const gasLimit = (estimatedGas * 120n) / 100n;

    if (gasLimit > MAX_GAS_LIMIT) {
      throw new Error(
        `Estimated gas ${gasLimit} exceeds maximum allowed (${MAX_GAS_LIMIT})`
      );
    }

    // Get current fee data
    const feeData = await this._walletManager.provider.getFeeData();
    const nonce = await this._getSecureNonce();

    // Build the transaction details for review
    const txDetails = {
      contract: sanitizedAddress,
      contractLabel: contractInfo.label,
      function: functionName,
      arguments: sanitizedArgs.map(String),
      value: ethers.formatEther(valueWei) + " ETH",
      estimatedGas: gasLimit.toString(),
      maxFeePerGas: feeData.maxFeePerGas
        ? ethers.formatUnits(feeData.maxFeePerGas, "gwei") + " gwei"
        : "N/A",
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
        ? ethers.formatUnits(feeData.maxPriorityFeePerGas, "gwei") + " gwei"
        : "N/A",
      nonce: nonce,
      network: this._walletManager.networkName,
    };

    return {
      txDetails,
      execute: async () => {
        // Re-enforce rate limit at execution time
        this._enforceRateLimit();

        const overrides = {
          gasLimit: gasLimit,
          nonce: nonce,
          value: valueWei,
        };

        if (feeData.maxFeePerGas) {
          overrides.maxFeePerGas = feeData.maxFeePerGas;
          overrides.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
        }

        const tx = await contract[functionName](
          ...sanitizedArgs,
          overrides
        );

        this._lastTransactionTime = Date.now();

        // SECURE: Only log transaction hash, not full details with sensitive data
        console.log(`Transaction submitted: ${tx.hash}`);
        console.log("Waiting for confirmation...");

        const receipt = await tx.wait(1); // Wait for 1 confirmation
        return {
          hash: receipt.hash,
          blockNumber: receipt.blockNumber,
          gasUsed: receipt.gasUsed.toString(),
          status: receipt.status === 1 ? "success" : "failed",
        };
      },
    };
  }
}

// ============================================================
// INTERACTIVE CLI
// ============================================================

class DAppCLI {
  constructor() {
    this._walletManager = new SecureWalletManager();
    this._txBuilder = null;
    this._rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
    });
  }

  _prompt(question) {
    return new Promise((resolve) => {
      this._rl.question(question, (answer) => {
        resolve(answer);
      });
    });
  }

  async _confirmAction(details) {
    console.log("\n" + "=".repeat(60));
    console.log("TRANSACTION REVIEW");
    console.log("=".repeat(60));
    for (const [key, value] of Object.entries(details)) {
      if (Array.isArray(value)) {
        console.log(`  ${key}: [${value.join(", ")}]`);
      } else {
        console.log(`  ${key}: ${value}`);
      }
    }
    console.log("=".repeat(60));

    const confirmation = await this._prompt(
      '\nType "CONFIRM" to proceed, anything else to cancel: '
    );
    return confirmation.trim() === "CONFIRM";
  }

  async handleConnect() {
    const network = await this._prompt(
      `Select network (${Object.keys(SUPPORTED_NETWORKS).join(", ")}): `
    );
    await this._walletManager.connect(network);
    await this._walletManager.loadWalletFromEnv();
    this._txBuilder = new SecureTransactionBuilder(this._walletManager);
  }

  async handleAddContract() {
    const address = await this._prompt("Contract address: ");
    const label = await this._prompt("Contract label/name: ");
    console.log(
      'Enter ABI (JSON array, single line, or type "file:" followed by nothing for manual entry):'
    );
    const abiInput = await this._prompt("ABI: ");

    if (!InputValidator.isValidABI(abiInput)) {
      console.error("Invalid ABI format. Must be a valid JSON array.");
      return;
    }

    ContractAllowlistManager.addContract(address, abiInput, label);
  }

  async handleReadCall() {
    if (!this._txBuilder) {
      console.error("Connect to a network first.");
      return;
    }

    const address = await this._prompt("Contract address: ");
    const functionName = await this._prompt("Function name: ");
    const argsInput = await this._prompt(
      "Arguments (comma-separated, or empty): "
    );

    const args = argsInput.trim()
      ? argsInput.split(",").map((a) => a.trim())
      : [];

    try {
      const result = await this._txBuilder.buildReadTransaction(
        address,
        functionName,
        args
      );
      console.log(`\nResult: ${result}`);
    } catch (error) {
      console.error(`Read call failed: ${error.message}`);
    }
  }

  async handleWriteCall() {
    if (!this._txBuilder) {
      console.error("Connect to a network first.");
      return;
    }

    const address = await this._prompt("Contract address: ");
    const functionName = await this._prompt("Function name: ");
    const argsInput = await this._prompt(
      "Arguments (comma-separated, or empty): "
    );
    const value = await this._prompt("ETH value to send (0 for none): ");

    const args = argsInput.trim()
      ? argsInput.split(",").map((a) => a.trim())
      : [];

    try {
      const { txDetails, execute } =
        await this._txBuilder.buildWriteTransaction(
          address,
          functionName,
          args,
          value
        );

      // SECURE: Require explicit confirmation before signing
      const confirmed = await this._confirmAction(txDetails);

      if (!confirmed) {
        console.log("Transaction cancelled.");
        return;
      }

      const receipt = await execute();
      console.log("\nTransaction confirmed!");
      console.log(`  Hash: ${receipt.hash}`);
      console.log(`  Block: ${receipt.blockNumber}`);
      console.log(`  Gas Used: ${receipt.gasUsed}`);
      console.log(`  Status: ${receipt.status}`);
    } catch (error) {
      console.error(`Write call failed: ${error.message}`);
    }
  }

  async handleListContracts() {
    ContractAllowlistManager.listContracts();
  }

  async handleCheckBalance() {
    if (!this._walletManager.provider || !this._walletManager.wallet) {
      console.error("Connect to a network first.");
      return;
    }
    const balance = await this._walletManager.provider.getBalance(
      this._walletManager.wallet.address
    );
    const maskedAddress = `${this._walletManager.wallet.address.slice(0, 6)}...${this._walletManager.wallet.address.slice(-4)}`;
    console.log(
      `Balance of ${maskedAddress}: ${ethers.formatEther(balance)} ETH`
    );
  }

  printMenu() {
    console.log("\n" + "=".repeat(40));
    console.log("  Secure DApp Transaction Builder");
    console.log("=".repeat(40));
    console.log("  1. Connect to network & load wallet");
    console.log("  2. Add contract to allowlist");
    console.log("  3. List allowlisted contracts");
    console.log("  4. Read from contract (no signing)");
    console.log("  5. Write to contract (signs tx)");
    console.log("  6. Check wallet balance");
    console.log("  7. Exit");
    console.log("=".repeat(40));
  }

  async run() {
    console.log("\nSecure DApp Transaction Builder");
    console.log(
      "NOTE: Set WALLET_PRIVATE_KEY environment variable before starting.\n"
    );

    let running = true;
    while (running) {
      this.printMenu();
      const choice = await this._prompt("\nSelect option: ");

      try {
        switch (choice.trim()) {
          case "1":
            await this.handleConnect();
            break;
          case "2":
            await this.handleAddContract();
            break;
          case "3":
            await this.handleListContracts();
            break;
          case "4":
            await this.handleReadCall();
            break;
          case "5":
            await this.handleWriteCall();
            break;
          case "6":
            await this.handleCheckBalance();
            break;
          case "7":
            running = false;
            console.log("Goodbye.");
            break;
          default:
            console.log("Invalid option. Please select 1-7.");
        }
      } catch (error) {
        console.error(`Error: ${error.message}`);
      }
    }

    this._rl.close();
  }
}

// ============================================================
// ENTRY POINT
// ============================================================

async function main() {
  const cli = new DAppCLI();
  await cli.run();
}

main().catch((error) => {
  // SECURE: Don't leak stack traces in production
  console.error(`Fatal error: ${error.message}`);
  process.exit(1);
});

module.exports = {
  InputValidator,
  SecureWalletManager,
  ContractAllowlistManager,
  SecureTransactionBuilder,
  DAppCLI,
};